import{_ as o,o as a,c as l,an as i}from"./chunks/framework.DKgvuBLA.js";const h=JSON.parse('{"title":"खेल का मैदान","description":"","frontmatter":{},"headers":[],"relativePath":"hi/playground/index.md","filePath":"hi/playground/index.md"}'),d={name:"hi/playground/index.md"};function t(r,e,c,p,s,n){return a(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="खेल-का-मैदान" tabindex="-1">खेल का मैदान <a class="header-anchor" href="#खेल-का-मैदान" aria-label="Permalink to &quot;खेल का मैदान&quot;">​</a></h1><p>उपयोग के मामले से विभाजित:</p><ul><li><a href="/hi/playground/configs"><code>Configs Playground</code></a>: पूर्ण संपादन योग्य विकल्पों के साथ समृद्ध डेमो।</li><li><a href="/hi/playground/shapes"><code>Shapes Playground</code></a>: <code>shape.type</code> के लिए केंद्रित डेमो, जहां उपलब्ध हो वहां आकार-विशिष्ट विकल्पों के साथ।</li><li><a href="/hi/playground/presets"><code>Presets Playground</code></a>: आधिकारिक प्रीसेट-नाम डेमो (<code>{ preset: &quot;...&quot; }</code>)।</li><li><a href="/hi/playground/palettes"><code>Palettes Playground</code></a>: प्रीसेट प्रोजेक्ट से पैलेट-केंद्रित डेमो।</li><li><a href="/hi/playground/bundles"><code>Bundles Playground</code></a>: <code>@tsparticles/confetti</code>, <code>@tsparticles/fireworks</code>, <code>@tsparticles/particles</code>, और <code>@tsparticles/ribbons</code> के लिए समर्पित खेल के मैदान।</li></ul><p>निष्पादन हमेशा <strong>केवल उपयोगकर्ता-ट्रिगर</strong> होता है (कोई ऑटोप्ले नहीं)।</p><h2 id="साझा-प्रवाह" tabindex="-1">साझा प्रवाह <a class="header-anchor" href="#साझा-प्रवाह" aria-label="Permalink to &quot;साझा प्रवाह&quot;">​</a></h2><p>खेल के मैदानों में लेआउट एक समान है:</p><ol><li><p>पहले कैनवास पूर्वावलोकन.</p></li><li><p>प्रारंभ/रोकें/फिर से शुरू करें/नष्ट करने के लिए नियंत्रण।</p></li><li><p>विकल्पों के लिए JSON संपादक।</p></li><li><p>मेनू से एक डेमो चुनें.</p></li><li><p>इसे चलाने के लिए <code>Start</code> दबाएँ (कोई ऑटोप्ले नहीं)।</p></li><li><p>संपादक में JSON संपादित करें।</p></li><li><p>अपने नए विकल्पों के साथ पुनः लोड करने के लिए <code>Start</code> को फिर से दबाएँ।</p></li><li><p>प्रदर्शन और सीपीयू उपयोग को नियंत्रित करने के लिए <code>Pause</code>/<code>Resume</code> का उपयोग करें।</p></li></ol><blockquote><p>नोट: <code>Destroy</code> कंटेनर इंस्टेंस को पूरी तरह से रिलीज़ करता है।</p></blockquote><h2 id="सुझाया-गया-वर्कफ़्लो" tabindex="-1">सुझाया गया वर्कफ़्लो <a class="header-anchor" href="#सुझाया-गया-वर्कफ़्लो" aria-label="Permalink to &quot;सुझाया गया वर्कफ़्लो&quot;">​</a></h2><ul><li>प्रभाव स्थिर होने तक यहां प्रोटोटाइप करें।</li><li>अंतिम JSON को अपने प्रोजेक्ट में कॉपी करें।</li><li>इसे एप्लिकेशन कोड में <code>ISourceOptions</code> के साथ टाइप करें।</li></ul>',10)])])}const _=o(d,[["render",t]]);export{h as __pageData,_ as default};
